		if type(_G) == "table" and type(_G.__RAYFIELD_COMMAND_PALETTE_EXEC_MODE) == "string" then
			return tostring(_G.__RAYFIELD_COMMAND_PALETTE_EXEC_MODE)
		end
		return "auto"
