			return {}
		end
		if type(okHistory) == "table" then
			return okHistory
		end
		if type(historyOrErr) == "table" then
			return historyOrErr
		end
		return {}
	end

	function RayfieldLibrary:ClearNotificationHistory()
		return withUIStateMethod("ClearNotificationHistory")
	end

