		local okFetch, sourceOrErr = pcall(httpGet, tostring(url))
		if not okFetch or type(sourceOrErr) ~= "string" or sourceOrErr == "" then
			warnFn("Rayfield Mod: [W_HTTP_LOADER_FALLBACK] " .. tostring(sourceOrErr))
