	end

	loadInitialState()

	return {
		resolveControlLabel = resolveControlLabel,
		setControlLabel = setControlLabel,
		getControlLabel = getControlLabel,
		resetControlLabel = resetControlLabel,
		setSystemLabel = setSystemLabel,
