	{ field = "RuntimeBindingsAIAssistantLib", module = "runtimeBindingsAIAssistant", mode = "required" },
	{ field = "RuntimeBindingsCommunicationLib", module = "runtimeBindingsCommunication", mode = "required" },
	{ field = "RuntimeBindingsLocalizationLib", module = "runtimeBindingsLocalization", mode = "required" },
	{ field = "RuntimeBindingsUIEventsLib", module = "runtimeBindingsUIEvents", mode = "required" },
	{ field = "RuntimeBindingsMovementEventsLib", module = "runtimeBindingsMovementEvents", mode = "required" },
	{ field = "RuntimeBindingsCombatEventsLib", module = "runtimeBindingsCombatEvents", mode = "required" },
	{ field = "WorkspaceServiceLib", module = "runtimeWorkspaceService", mode = "required" },
	{ field = "CommandPaletteServiceLib", module = "runtimeCommandPaletteService", mode = "required" },
	{ field = "CommandPaletteSearchAlgorithmsLib", module = "runtimeCommandPaletteSearchAlgorithms", mode = "required" },
	{ field = "SmartSearchServiceLib", module = "runtimeSmartSearchService", mode = "required" },
	{ field = "MultiInstanceBridgeServiceLib", module = "runtimeMultiInstanceBridgeService", mode = "required" },
	{ field = "AutomationEngineServiceLib", module = "runtimeAutomationEngineService", mode = "required" },
	{ field = "UsageAnalyticsServiceLib", module = "runtimeUsageAnalyticsService", mode = "required" },
	{ field = "MacroRecorderServiceLib", module = "runtimeMacroRecorderService", mode = "required" },
	{ field = "DevExperienceServiceLib", module = "runtimeDevExperienceService", mode = "required" },
	{ field = "LocalizationServiceLib", module = "runtimeLocalizationService", mode = "required" },
	{ field = "UIStringRegistryLib", module = "runtimeUIStringRegistry", mode = "required" },
	{ field = "ShareCodeServiceLib", module = "runtimeShareCodeService", mode = "required" },
	{ field = "EntryDiscordInviteServiceLib", module = "entryDiscordInviteService", mode = "required" },
	{ field = "EntryKeySystemServiceLib", module = "entryKeySystemService", mode = "required" },
	{ field = "RuntimeModuleLoaderLib", module = "runtimeModuleLoader", mode = "required" },
	{ field = "PerformanceHUDServiceLib", module = "runtimePerformanceHUDService", mode = "required" },
	{ field = "RuntimeApiLib", module = "runtimeApi", mode = "required" }
}

function RuntimeModuleRegistryLoader.load(options)
	options = type(options) == "table" and options or {}
	local requireModule = type(options.requireModule) == "function" and options.requireModule or nil
	local optionalModule = type(options.optionalModule) == "function" and options.optionalModule or nil
	local fallbacks = type(options.fallbacks) == "table" and options.fallbacks or {}

	if not requireModule then
		error("RuntimeModuleRegistryLoader.load requires requireModule")
	end
	if not optionalModule then
		error("RuntimeModuleRegistryLoader.load requires optionalModule")
	end

	local modules = {}
	for _, spec in ipairs(MODULE_SPECS) do
		if spec.mode == "required" then
			modules[spec.field] = requireModule(spec.module)
		else
			modules[spec.field] = optionalModule(spec.module, fallbacks[spec.fallback], spec.hint)
		end
	end
	return modules
end

return RuntimeModuleRegistryLoader
]])
put("src/core/runtime/multi-instance-bridge-service.lua", [[local MultiInstanceBridgeService = {}

local function defaultClone(value, seen)
	local valueType = type(value)
	if valueType ~= "table" then
		return value
	end
	seen = seen or {}
	if seen[value] then
		return seen[value]
	end
	local out = {}
	seen[value] = out
	for key, nested in pairs(value) do
		out[defaultClone(key, seen)] = defaultClone(nested, seen)
	end
	return out
end

local function nowClock()
	return os.clock()
end

local function nowStamp()
	if type(os.date) == "function" then
		return os.date("!%Y-%m-%dT%H:%M:%SZ")
	end
	return tostring(nowClock())
end

local function normalizeMode(mode)
	local normalized = string.lower(tostring(mode or "auto"))
	if normalized ~= "auto" and normalized ~= "file" and normalized ~= "http" and normalized ~= "none" then
		return "auto"
	end
	return normalized
end

local function readJson(HttpService, text)
	if type(HttpService) ~= "table" or type(HttpService.JSONDecode) ~= "function" then
		return nil
	end
	local ok, decoded = pcall(HttpService.JSONDecode, HttpService, tostring(text or ""))
	if not ok then
		return nil
	end
	return decoded
end

local function writeJson(HttpService, value)
	if type(HttpService) ~= "table" or type(HttpService.JSONEncode) ~= "function" then
		return nil
	end
	local ok, encoded = pcall(HttpService.JSONEncode, HttpService, value)
	if not ok then
		return nil
	end
	return encoded
end

local function ensureFolderPath(path, makefolderFn, isfolderFn)
	if type(path) ~= "string" or path == "" then
		return true
	end
	if type(makefolderFn) ~= "function" then
		return false
	end
	local normalized = path:gsub("\\", "/")
	local current = ""
	for part in normalized:gmatch("[^/]+") do
		current = current == "" and part or (current .. "/" .. part)
		local exists = false
		if type(isfolderFn) == "function" then
			local okExists, result = pcall(isfolderFn, current)
			exists = okExists and result == true
		end
		if not exists then
			local okMake = pcall(makefolderFn, current)
			if not okMake then
				return false
			end
		end
	end
	return true
end

local function inferRequestFunction()
	return (syn and syn.request)
		or (fluxus and fluxus.request)
		or (http and http.request)
		or http_request
		or request
end

function MultiInstanceBridgeService.create(ctx)
	ctx = ctx or {}
	local cloneValue = type(ctx.cloneValue) == "function" and ctx.cloneValue or defaultClone
	local HttpService = ctx.HttpService
	local notify = type(ctx.notify) == "function" and ctx.notify or nil
	local onMessage = type(ctx.onMessage) == "function" and ctx.onMessage or nil
	local globalEnv = type(_G) == "table" and _G or nil

	local mode = normalizeMode((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_MODE) or ctx.mode or "auto")
	local channel = tostring((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_CHANNEL) or ctx.channel or "default")
	if channel == "" then
		channel = "default"
	end
	local endpoint = tostring((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_ENDPOINT) or ctx.endpoint or "")
	local filePath = tostring((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_FILE_PATH) or ctx.filePath or ("Rayfield/Bridge/" .. channel .. ".jsonl"))
	local pollIntervalSec = tonumber((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_POLL_SEC) or ctx.pollIntervalSec or 1) or 1
	pollIntervalSec = math.max(0.2, pollIntervalSec)
	local historyLimit = tonumber((globalEnv and globalEnv.__RAYFIELD_MULTI_BRIDGE_HISTORY_LIMIT) or ctx.historyLimit or 120) or 120
	historyLimit = math.max(20, math.floor(historyLimit))
	local requestFn = type(ctx.requestFn) == "function" and ctx.requestFn or inferRequestFunction()

	local instanceId = tostring((globalEnv and globalEnv.__RAYFIELD_INSTANCE_ID) or (ctx.instanceId or ""))
	if instanceId == "" then
		local generated = nil
		if type(HttpService) == "table" and type(HttpService.GenerateGUID) == "function" then
			local okGuid, guid = pcall(HttpService.GenerateGUID, HttpService, false)
			if okGuid and type(guid) == "string" and guid ~= "" then
				generated = guid
			end
		end
		instanceId = generated or ("instance-" .. tostring(math.floor(nowClock() * 100000)))
	end

	local appendfileFn = type(appendfile) == "function" and appendfile or nil
	local readfileFn = type(readfile) == "function" and readfile or nil
	local writefileFn = type(writefile) == "function" and writefile or nil
	local isfileFn = type(isfile) == "function" and isfile or nil
	local makefolderFn = type(makefolder) == "function" and makefolder or nil
	local isfolderFn = type(isfolder) == "function" and isfolder or nil

	local messageHistory = {}
	local seen = {}
	local polling = false
	local pollToken = 0

	local function pushHistory(message)
		table.insert(messageHistory, message)
		while #messageHistory > historyLimit do
			table.remove(messageHistory, 1)
		end
	end

	local function hasFileBridge()
		return type(readfileFn) == "function" and (type(appendfileFn) == "function" or type(writefileFn) == "function")
	end

	local function buildMessageId()
		local suffix = tostring(math.floor(nowClock() * 1000000))
		return string.format("%s:%s", instanceId, suffix)
	end

	local function ensureFileFolder()
		if type(filePath) ~= "string" or filePath == "" then
			return false
		end
		local folder = string.match(filePath, "^(.*)[/\\][^/\\]+$")
		if not folder then
			return true
		end
		return ensureFolderPath(folder, makefolderFn, isfolderFn)
	end

	local function appendFileLine(line)
		if type(line) ~= "string" or line == "" then
			return false, "Bridge payload is empty."
		end
		if not ensureFileFolder() then
			return false, "Bridge folder unavailable."
		end
		if appendfileFn then
			local okAppend = pcall(appendfileFn, filePath, line .. "\n")
			if okAppend then
				return true, "ok"
			end
		end
		if writefileFn and readfileFn then
			local existing = ""
			if not isfileFn or pcall(isfileFn, filePath) then
				local okRead, readResult = pcall(readfileFn, filePath)
				if okRead and type(readResult) == "string" then
					existing = readResult
				end
			end
			local okWrite = pcall(writefileFn, filePath, existing .. line .. "\n")
			if okWrite then
				return true, "ok"
			end
		end
		return false, "Bridge file write failed."
	end

	local function sendViaHttp(envelope)
		if endpoint == "" then
			return false, "Bridge endpoint unavailable."
		end
		local encoded = writeJson(HttpService, envelope)
		if not encoded then
			return false, "Bridge JSON encoder unavailable."
		end

		if type(requestFn) == "function" then
			local okRequest, response = pcall(requestFn, {
				Url = endpoint,
				Method = "POST",
				Headers = {
					["Content-Type"] = "application/json"
				},
				Body = encoded
			})
			if not okRequest then
				return false, tostring(response)
			end
			if type(response) == "table" then
				local statusCode = tonumber(response.StatusCode) or 0
				if statusCode >= 200 and statusCode < 300 then
					return true, "ok"
				end
				return false, "HTTP status " .. tostring(statusCode)
			end
			return true, "ok"
		end

		if type(HttpService) == "table" and type(HttpService.PostAsync) == "function" then
			local okPost, postErr = pcall(HttpService.PostAsync, HttpService, endpoint, encoded, Enum.HttpContentType.ApplicationJson, false)
			if okPost then
				return true, "ok"
			end
			return false, tostring(postErr)
		end

		return false, "HTTP request bridge unavailable."
	end

	local function normalizeEnvelope(rawMessage)
		if type(rawMessage) ~= "table" then
			return nil
		end
		local envelope = cloneValue(rawMessage)
		envelope.id = tostring(envelope.id or "")
		if envelope.id == "" then
			return nil
		end
		envelope.kind = tostring(envelope.kind or "signal")
		envelope.channel = tostring(envelope.channel or "")
		envelope.from = tostring(envelope.from or "")
		envelope.to = tostring(envelope.to or "all")
		envelope.at = tostring(envelope.at or nowStamp())
		envelope.payload = type(envelope.payload) == "table" and envelope.payload or {}
		return envelope
	end

	local function acceptIncoming(envelope)
		if type(envelope) ~= "table" then
			return false
		end
		if envelope.channel ~= channel then
			return false
		end
		if envelope.from == instanceId then
			return false
		end
		if envelope.to ~= "all" and envelope.to ~= instanceId then
			return false
		end
		local seenId = tostring(envelope.id or "")
		if seenId == "" or seen[seenId] == true then
			return false
		end
		seen[seenId] = true
		pushHistory(envelope)
		if type(onMessage) == "function" then
			pcall(onMessage, cloneValue(envelope))
		end
		return true
	end

	local function readFileMessages()
		if not hasFileBridge() then
			return {}
		end
		local okRead, content = pcall(readfileFn, filePath)
		if not okRead or type(content) ~= "string" or content == "" then
			return {}
		end
		local out = {}
		for line in content:gmatch("[^\r\n]+") do
			local decoded = readJson(HttpService, line)
			local envelope = normalizeEnvelope(decoded)
			if envelope then
				table.insert(out, envelope)
			end
		end
		return out
	end

	local function fetchHttpMessages(limit)
		if endpoint == "" then
			return {}
		end
		local queryUrl = string.format("%s?channel=%s&limit=%d", endpoint, channel, tonumber(limit) or 50)
		local responseBody = nil

		if type(requestFn) == "function" then
			local okRequest, response = pcall(requestFn, {
				Url = queryUrl,
				Method = "GET"
			})
			if okRequest and type(response) == "table" then
				responseBody = response.Body or response.body or response.ResponseBody
			end
		elseif type(HttpService) == "table" and type(HttpService.GetAsync) == "function" then
			local okGet, result = pcall(HttpService.GetAsync, HttpService, queryUrl, false)
			if okGet then
				responseBody = result
			end
		end

		if type(responseBody) ~= "string" or responseBody == "" then
			return {}
		end

		local decoded = readJson(HttpService, responseBody)
		if type(decoded) ~= "table" then
			return {}
		end

		local payloadList = decoded
		if type(decoded.messages) == "table" then
			payloadList = decoded.messages
		end
		if type(payloadList) ~= "table" then
			return {}
		end

		local out = {}
		for _, raw in ipairs(payloadList) do
			local envelope = normalizeEnvelope(raw)
			if envelope then
				table.insert(out, envelope)
			end
		end
		return out
	end

	local function modeForOperation(overrideMode)
		local target = normalizeMode(overrideMode or mode)
		if target ~= "auto" then
			return target
		end
		if hasFileBridge() or endpoint ~= "" then
			return "auto"
		end
		return "none"
	end

	local function publish(kind, payload, options)
		options = type(options) == "table" and options or {}
		local resolvedMode = modeForOperation(options.mode)
		if resolvedMode == "none" then
			return false, "Bridge mode is disabled.", nil
		end

		local envelope = {
			id = buildMessageId(),
			kind = tostring(kind or "signal"),
			channel = channel,
			from = instanceId,
			to = tostring(options.target or "all"),
			at = nowStamp(),
			payload = type(payload) == "table" and cloneValue(payload) or {
				value = payload
			}
		}

		local okSend, sendMsg = false, "Unknown bridge mode."
		if resolvedMode == "file" then
			local encoded = writeJson(HttpService, envelope)
			if not encoded then
				return false, "Bridge JSON encoder unavailable.", nil
			end
			okSend, sendMsg = appendFileLine(encoded)
		elseif resolvedMode == "http" then
			okSend, sendMsg = sendViaHttp(envelope)
		elseif resolvedMode == "auto" then
			local encoded = writeJson(HttpService, envelope)
			if encoded and hasFileBridge() then
				okSend, sendMsg = appendFileLine(encoded)
				if okSend then
					seen[envelope.id] = true
					pushHistory(cloneValue(envelope))
					return true, "Bridge message sent (file).", envelope
				end
			end
			okSend, sendMsg = sendViaHttp(envelope)
		end

		if okSend then
			seen[envelope.id] = true
			pushHistory(cloneValue(envelope))
			return true, "Bridge message sent (" .. resolvedMode .. ").", envelope
		end
		return false, tostring(sendMsg or "Bridge send failed."), envelope
	end

	local function poll(limit, options)
		options = type(options) == "table" and options or {}
		local resolvedMode = modeForOperation(options.mode)
		if resolvedMode == "none" then
			return false, "Bridge mode is disabled.", {}
		end
		local newMessages = {}

		local function ingest(messages)
			for _, message in ipairs(type(messages) == "table" and messages or {}) do
				if acceptIncoming(message) then
					table.insert(newMessages, cloneValue(message))
				end
			end
		end

		if resolvedMode == "file" then
			ingest(readFileMessages())
		elseif resolvedMode == "http" then
			ingest(fetchHttpMessages(limit))
		else
			ingest(readFileMessages())
			ingest(fetchHttpMessages(limit))
		end

		return true, "Bridge poll completed.", newMessages
	end

	local function startPolling()
		if polling then
			return true, "Bridge polling already active."
		end
		polling = true
		pollToken += 1
		local token = pollToken
		task.spawn(function()
			while polling and token == pollToken do
				local okPoll, pollMsg = poll(120, {})
				if not okPoll and notify then
					notify({
						Title = "Bridge Poll",
						Content = tostring(pollMsg),
						Duration = 3
					})
				end
				task.wait(pollIntervalSec)
			end
		end)
		return true, "Bridge polling started."
	end

	local function stopPolling()
		if not polling then
			return true, "Bridge polling already stopped."
		end
		polling = false
		pollToken += 1
		return true, "Bridge polling stopped."
	end

	local function listMessages(limit, kind)
		local targetKind = tostring(kind or "")
		local maxCount = tonumber(limit) or #messageHistory
		maxCount = math.max(1, math.floor(maxCount))
		local out = {}
		for index = #messageHistory, 1, -1 do
			local item = messageHistory[index]
			if targetKind == "" or tostring(item.kind) == targetKind then
				table.insert(out, cloneValue(item))
				if #out >= maxCount then
					break
				end
			end
		end
		return out
	end

	local function setMessageHandler(handler)
		if type(handler) ~= "function" then
			onMessage = nil
			return true, "Bridge message handler cleared."
		end
		onMessage = handler
		return true, "Bridge message handler updated."
	end

	local service = {
		sendSignal = function(command, payload, options)
			local safeCommand = tostring(command or "")
			if safeCommand == "" then
				return false, "Signal command is required."
			end
			return publish("signal", {
				command = safeCommand,
				data = cloneValue(payload),
				source = "rayfield"
			}, options)
		end,
		sendChat = function(text, options)
			local messageText = tostring(text or ""):gsub("^%s+", ""):gsub("%s+$", "")
			if messageText == "" then
				return false, "Chat message is empty."
			end
			return publish("chat", {
				text = messageText,
				source = "rayfield"
			}, options)
		end,
		poll = poll,
		startPolling = startPolling,
		stopPolling = stopPolling,
		isPolling = function()
			return polling == true
		end,
		listMessages = listMessages,
		clearHistory = function()
			table.clear(messageHistory)
			return true, "Bridge history cleared."
		end,
		setMessageHandler = setMessageHandler,
		getStatus = function()
			return {
				mode = mode,
				channel = channel,
				instanceId = instanceId,
				filePath = filePath,
				endpoint = endpoint,
				polling = polling == true,
				pollIntervalSec = pollIntervalSec
			}
		end
	}

	if globalEnv then
		globalEnv.__RAYFIELD_MULTI_BRIDGE = service
	end

	return service
end

return MultiInstanceBridgeService
]])
put("src/core/runtime/performance-hud-service.lua", [[local PerformanceHUDService = {}

local DEFAULT_POSITION = { x = 16, y = 52 }
local DEFAULT_SIZE = { width = 260, height = 176 }
local DEFAULT_DOCK = "top_left"
local TOP_SAFE_OFFSET = 52
local VIEWPORT_PADDING = 8

local function clampNumber(value, minValue, maxValue, fallback)
	local numeric = tonumber(value)
	if not numeric then
		return fallback
	end
	if numeric < minValue then
		return minValue
	end
	if numeric > maxValue then
		return maxValue
	end
	return numeric
end

local function cloneValue(value, seen)
	if type(value) ~= "table" then
		return value
	end
	seen = seen or {}
	if seen[value] then
		return seen[value]
	end
	local out = {}
	seen[value] = out
	for key, nested in pairs(value) do
		out[cloneValue(key, seen)] = cloneValue(nested, seen)
	end
	return out
end

local function normalizeDock(value)
	local dock = string.lower(tostring(value or ""))
	if dock == "top_left"
		or dock == "top_right"
		or dock == "bottom_left"
		or dock == "bottom_right"
		or dock == "center"
		or dock == "custom" then
		return dock
	end
	return DEFAULT_DOCK
end

function PerformanceHUDService.create(ctx)
	ctx = ctx or {}
	local Main = ctx.Main
	local UserInputService = ctx.UserInputService
	local loadState = type(ctx.loadState) == "function" and ctx.loadState or nil
	local saveState = type(ctx.saveState) == "function" and ctx.saveState or nil
	local getRuntimeDiagnostics = type(ctx.getRuntimeDiagnostics) == "function" and ctx.getRuntimeDiagnostics or function()
		return {}
	end
	local getVisibilityState = type(ctx.getVisibilityState) == "function" and ctx.getVisibilityState or function()
		return { hidden = false, minimized = false }
	end
	local getMacroState = type(ctx.getMacroState) == "function" and ctx.getMacroState or function()
		return { recording = false, executing = false }
	end
	local getAutomationSummary = type(ctx.getAutomationSummary) == "function" and ctx.getAutomationSummary or function()
		return { scheduled = 0, rules = 0 }
	end
	local localize = type(ctx.localize) == "function" and ctx.localize or function(_, fallback)
		return tostring(fallback or "")
	end
	local function L(key, fallback)
		local okValue, value = pcall(localize, key, fallback)
		if okValue and type(value) == "string" and value ~= "" then
			return value
		end
		return tostring(fallback or key or "")
	end

	local defaultEnabled = not (type(_G) == "table" and _G.__RAYFIELD_PERF_HUD_ENABLED == false)
	local defaultHz = clampNumber(type(_G) == "table" and _G.__RAYFIELD_PERF_HUD_UPDATE_HZ or 4, 1, 30, 4)
	local defaultOpacity = clampNumber(type(_G) == "table" and _G.__RAYFIELD_PERF_HUD_OPACITY or 0.75, 0.15, 1, 0.75)

	local state = {
		enabled = defaultEnabled,
		updateHz = defaultHz,
		opacity = defaultOpacity,
		position = cloneValue(DEFAULT_POSITION),
		size = cloneValue(DEFAULT_SIZE),
		dock = DEFAULT_DOCK,
		visible = false,
		lastUpdatedAt = 0,
		lastMetrics = {},
		registeredProviders = {}
	}

	local refs = {}
	local destroyed = false
	local providers = {}
	local connections = {}
	local fpsState = {
		lastClock = os.clock(),
		smoothed = 0
	}

	local function disconnectAll()
		for index = #connections, 1, -1 do
			local connection = connections[index]
			if connection then
				pcall(function()
					connection:Disconnect()
				end)
			end
			connections[index] = nil
		end
	end

	local function getHudParent()
		if Main and Main.Parent then
			return Main.Parent
		end
		return nil
	end

	local function getParentAbsoluteSize()
		local parent = getHudParent()
		if parent and parent.AbsoluteSize then
			return parent.AbsoluteSize
		end
		return nil
	end

	local function clampStateSize()
		state.size.width = math.max(220, math.floor(tonumber(state.size.width) or DEFAULT_SIZE.width))
		state.size.height = math.max(140, math.floor(tonumber(state.size.height) or DEFAULT_SIZE.height))
	end

	local function clampStatePosition()
		state.position.x = math.max(0, math.floor(tonumber(state.position.x) or DEFAULT_POSITION.x))
		state.position.y = math.max(0, math.floor(tonumber(state.position.y) or DEFAULT_POSITION.y))
		local parentSize = getParentAbsoluteSize()
		if not parentSize then
			return
		end
		local maxX = math.max(0, parentSize.X - state.size.width - VIEWPORT_PADDING)
		local maxY = math.max(0, parentSize.Y - state.size.height - VIEWPORT_PADDING)
		state.position.x = math.min(state.position.x, maxX)
		state.position.y = math.min(state.position.y, maxY)
	end

	local function resolveDockPosition(dock)
		local parentSize = getParentAbsoluteSize()
		local key = normalizeDock(dock)
		if key == "custom" then
			return state.position.x, state.position.y
		end
		if not parentSize then
			if key == "top_right" then
				return DEFAULT_POSITION.x + 140, DEFAULT_POSITION.y
			elseif key == "bottom_left" then
				return DEFAULT_POSITION.x, DEFAULT_POSITION.y + 120
			elseif key == "bottom_right" then
				return DEFAULT_POSITION.x + 140, DEFAULT_POSITION.y + 120
			elseif key == "center" then
				return DEFAULT_POSITION.x + 70, DEFAULT_POSITION.y + 60
			end
			return DEFAULT_POSITION.x, DEFAULT_POSITION.y
		end
		local maxX = math.max(0, parentSize.X - state.size.width - VIEWPORT_PADDING)
		local maxY = math.max(0, parentSize.Y - state.size.height - VIEWPORT_PADDING)
		if key == "top_right" then
			return maxX, TOP_SAFE_OFFSET
		elseif key == "bottom_left" then
			return VIEWPORT_PADDING, maxY
		elseif key == "bottom_right" then
			return maxX, maxY
		elseif key == "center" then
			return math.max(0, math.floor((parentSize.X - state.size.width) / 2)), math.max(0, math.floor((parentSize.Y - state.size.height) / 2))
		end
		return VIEWPORT_PADDING, TOP_SAFE_OFFSET
	end

	local function makePersistedSnapshot()
		return {
			updateHz = state.updateHz,
			opacity = state.opacity,
			position = {
				x = state.position.x,
				y = state.position.y
			},
			size = {
				width = state.size.width,
				height = state.size.height
			},
			dock = state.dock
		}
	end

	local function persistState()
		if type(saveState) ~= "function" then
			return
		end
		pcall(saveState, makePersistedSnapshot())
	end

	local function applyPersistedState(raw)
		if type(raw) ~= "table" then
			return
		end
		if raw.updateHz ~= nil then
			state.updateHz = clampNumber(raw.updateHz, 1, 30, state.updateHz)
		end
		if raw.opacity ~= nil then
			state.opacity = clampNumber(raw.opacity, 0.15, 1, state.opacity)
		end
		if type(raw.position) == "table" then
			state.position.x = math.floor(tonumber(raw.position.x or raw.position.X) or state.position.x)
			state.position.y = math.floor(tonumber(raw.position.y or raw.position.Y) or state.position.y)
		end
		if type(raw.size) == "table" then
			state.size.width = math.floor(tonumber(raw.size.width or raw.size.w) or state.size.width)
			state.size.height = math.floor(tonumber(raw.size.height or raw.size.h) or state.size.height)
		end
		state.dock = normalizeDock(raw.dock)
		clampStateSize()
		clampStatePosition()
	end

	if type(loadState) == "function" then
		local okLoad, persisted = pcall(loadState)
		if okLoad and type(persisted) == "table" then
			applyPersistedState(persisted)
		end
	end

	local function updateRootVisual()
		if not refs.Root then
			return
		end
		clampStateSize()
		clampStatePosition()
		refs.Root.BackgroundTransparency = 1 - state.opacity
		refs.Root.Visible = state.visible
		refs.Root.Position = UDim2.fromOffset(state.position.x, state.position.y)
		refs.Root.Size = UDim2.fromOffset(state.size.width, state.size.height)
	end

	local function ensureGui()
		if refs.Root and refs.Root.Parent then
			local parent = getHudParent()
			if parent and refs.Root.Parent ~= parent then
				refs.Root.Parent = parent
			end
			return true
		end
		local parent = getHudParent()
		if not parent then
			return false
		end

		local root = Instance.new("Frame")
		root.Name = "RayfieldPerformanceHUD"
		root.BorderSizePixel = 0
		root.ZIndex = 95
		root.BackgroundColor3 = Color3.fromRGB(16, 20, 26)
		root.Parent = parent

		local corner = Instance.new("UICorner")
		corner.CornerRadius = UDim.new(0, 8)
		corner.Parent = root

		local stroke = Instance.new("UIStroke")
		stroke.Transparency = 0.3
		stroke.Thickness = 1
		stroke.Color = Color3.fromRGB(150, 180, 255)
		stroke.Parent = root

		local titleBar = Instance.new("TextButton")
		titleBar.Name = "TitleBar"
		titleBar.BorderSizePixel = 0
		titleBar.BackgroundColor3 = Color3.fromRGB(24, 30, 42)
		titleBar.BackgroundTransparency = 0.15
		titleBar.Size = UDim2.new(1, -24, 0, 22)
		titleBar.Position = UDim2.fromOffset(0, 0)
		titleBar.Font = Enum.Font.GothamBold
		titleBar.TextSize = 11
		titleBar.TextXAlignment = Enum.TextXAlignment.Left
		titleBar.Text = "  " .. L("hud.title", "Performance HUD")
		titleBar.TextColor3 = Color3.fromRGB(235, 240, 255)
		titleBar.ZIndex = 96
		titleBar.Parent = root

		local closeButton = Instance.new("TextButton")
		closeButton.Name = "Close"
		closeButton.BorderSizePixel = 0
		closeButton.BackgroundColor3 = Color3.fromRGB(48, 60, 82)
		closeButton.BackgroundTransparency = 0.15
		closeButton.Size = UDim2.fromOffset(22, 22)
		closeButton.Position = UDim2.new(1, -22, 0, 0)
		closeButton.Font = Enum.Font.GothamBold
		closeButton.TextSize = 12
		closeButton.Text = "x"
		closeButton.TextColor3 = Color3.fromRGB(230, 235, 245)
		closeButton.ZIndex = 96
		closeButton.Parent = root

		local body = Instance.new("TextLabel")
		body.Name = "Body"
		body.BackgroundTransparency = 1
		body.Position = UDim2.fromOffset(8, 26)
		body.Size = UDim2.new(1, -16, 1, -34)
		body.Font = Enum.Font.Code
		body.TextSize = 12
		body.TextXAlignment = Enum.TextXAlignment.Left
		body.TextYAlignment = Enum.TextYAlignment.Top
		body.TextWrapped = true
		body.RichText = false
		body.TextColor3 = Color3.fromRGB(222, 232, 255)
		body.Text = L("hud.status.ready", "HUD ready.")
		body.ZIndex = 96
		body.Parent = root

		local resizeHandle = Instance.new("TextButton")
		resizeHandle.Name = "ResizeHandle"
		resizeHandle.BorderSizePixel = 0
		resizeHandle.BackgroundColor3 = Color3.fromRGB(64, 78, 104)
		resizeHandle.BackgroundTransparency = 0.1
		resizeHandle.Size = UDim2.fromOffset(16, 16)
		resizeHandle.Position = UDim2.new(1, -16, 1, -16)
		resizeHandle.Font = Enum.Font.GothamBold
		resizeHandle.TextSize = 10
		resizeHandle.Text = "<>"
		resizeHandle.TextColor3 = Color3.fromRGB(230, 240, 255)
		resizeHandle.ZIndex = 96
		resizeHandle.Parent = root

		refs = {
			Root = root,
			TitleBar = titleBar,
			CloseButton = closeButton,
			Body = body,
			ResizeHandle = resizeHandle
		}

		local dragging = false
		local dragStart = nil
		local positionStart = nil
		local resizing = false
		local sizeStart = nil

		table.insert(connections, titleBar.MouseButton1Down:Connect(function()
			dragging = true
			dragStart = UserInputService and UserInputService:GetMouseLocation() or Vector2.new(0, 0)
			positionStart = { x = state.position.x, y = state.position.y }
		end))

		table.insert(connections, resizeHandle.MouseButton1Down:Connect(function()
			resizing = true
			dragStart = UserInputService and UserInputService:GetMouseLocation() or Vector2.new(0, 0)
			sizeStart = { width = state.size.width, height = state.size.height }
		end))

		if UserInputService then
			table.insert(connections, UserInputService.InputEnded:Connect(function(input)
				if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
					local hadMovement = dragging or resizing
					dragging = false
					resizing = false
					if hadMovement then
						persistState()
					end
				end
			end))

			table.insert(connections, UserInputService.InputChanged:Connect(function(input)
				if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then
					return
				end
				if dragging and dragStart and positionStart then
					local current = UserInputService:GetMouseLocation()
					local deltaX = current.X - dragStart.X
					local deltaY = current.Y - dragStart.Y
					state.position.x = math.max(0, math.floor(positionStart.x + deltaX))
					state.position.y = math.max(0, math.floor(positionStart.y + deltaY))
					state.dock = "custom"
					updateRootVisual()
				elseif resizing and dragStart and sizeStart then
					local current = UserInputService:GetMouseLocation()
					local deltaX = current.X - dragStart.X
					local deltaY = current.Y - dragStart.Y
					state.size.width = math.max(220, math.floor(sizeStart.width + deltaX))
					state.size.height = math.max(140, math.floor(sizeStart.height + deltaY))
					state.dock = "custom"
					updateRootVisual()
				end
			end))
		end

		table.insert(connections, closeButton.MouseButton1Click:Connect(function()
			state.visible = false
			updateRootVisual()
			persistState()
		end))

		updateRootVisual()
		return true
	end

	local function readPingValue()
		local pingText = "N/A"
		local statsService = game and game:GetService("Stats") or nil
		if statsService then
			local okPing, pingValue = pcall(function()
				local network = statsService:FindFirstChild("Network")
				local serverStats = network and network:FindFirstChild("ServerStatsItem")
				local dataPing = serverStats and serverStats:FindFirstChild("Data Ping")
				return dataPing and dataPing:GetValueString() or nil
			end)
			if okPing and type(pingValue) == "string" and pingValue ~= "" then
				pingText = pingValue
			end
		end
		return pingText
	end

	local function collectDefaultMetrics()
		local diagnostics = getRuntimeDiagnostics() or {}
		local visibility = getVisibilityState() or {}
		local macroState = getMacroState() or {}
		local automation = getAutomationSummary() or {}
		local nowClock = os.clock()
		local delta = math.max(0.0001, nowClock - (fpsState.lastClock or nowClock))
		local instantFps = 1 / delta
		fpsState.lastClock = nowClock
		if fpsState.smoothed <= 0 then
			fpsState.smoothed = instantFps
		else
			fpsState.smoothed = (fpsState.smoothed * 0.82) + (instantFps * 0.18)
		end

		return {
			fps = math.floor(fpsState.smoothed + 0.5),
			ping = readPingValue(),
			activeTweens = tonumber(diagnostics.activeTweens) or 0,
			activeTextHandles = tonumber(diagnostics.activeTextHandles) or 0,
			ownershipScopes = tonumber(diagnostics.ownership and diagnostics.ownership.scopes) or 0,
			ownershipTasks = tonumber(diagnostics.ownership and diagnostics.ownership.tasks) or 0,
			visible = visibility.hidden ~= true,
			minimized = visibility.minimized == true,
			macroRecording = macroState.recording == true,
			macroExecuting = macroState.executing == true,
			scheduledActions = tonumber(automation.scheduled) or 0,
			automationRules = tonumber(automation.rules) or 0
		}
	end

	local function updateBody()
		if not refs.Body then
			return
		end
		local metrics = collectDefaultMetrics()
		for id, provider in pairs(providers) do
			local okProvider, providerValue = pcall(provider.fn, metrics, cloneValue(state))
			if okProvider and providerValue ~= nil then
				metrics[id] = providerValue
			end
		end
		state.lastMetrics = cloneValue(metrics)
		state.lastUpdatedAt = os.clock()

		local lines = {
			string.format(L("hud.metric.fps", "FPS: %s"), tostring(metrics.fps)),
			string.format(L("hud.metric.ping", "Ping: %s"), tostring(metrics.ping)),
			string.format(L("hud.metric.tweens_text", "Tweens: %s | Text: %s"), tostring(metrics.activeTweens), tostring(metrics.activeTextHandles)),
			string.format(L("hud.metric.ownership", "Ownership scopes/tasks: %s/%s"), tostring(metrics.ownershipScopes), tostring(metrics.ownershipTasks)),
			string.format(L("hud.metric.ui_state", "UI visible: %s | minimized: %s"), tostring(metrics.visible), tostring(metrics.minimized)),
			string.format(L("hud.metric.macro", "Macro rec/exec: %s/%s"), tostring(metrics.macroRecording), tostring(metrics.macroExecuting)),
			string.format(L("hud.metric.automation", "Automation scheduled/rules: %s/%s"), tostring(metrics.scheduledActions), tostring(metrics.automationRules))
		}
		refs.Body.Text = table.concat(lines, "\n")
	end

	local function openHUD()
		if destroyed then
			return false, L("hud.error.destroyed", "Performance HUD is destroyed.")
		end
		if not ensureGui() then
			return false, L("hud.error.parent_unavailable", "Performance HUD parent unavailable.")
		end
		state.enabled = true
		state.visible = true
		updateRootVisual()
		updateBody()
		persistState()
		return true, L("hud.status.opened", "Performance HUD opened.")
	end

	local function closeHUD()
		state.visible = false
		updateRootVisual()
		persistState()
		return true, L("hud.status.closed", "Performance HUD closed.")
	end

	local function toggleHUD()
		if state.visible then
			return closeHUD()
		end
		return openHUD()
	end

	local function configureHUD(options)
		options = type(options) == "table" and options or {}
		if options.enabled ~= nil then
			state.enabled = options.enabled == true
		end
		if options.updateHz ~= nil then
			state.updateHz = clampNumber(options.updateHz, 1, 30, state.updateHz)
		end
		if options.opacity ~= nil then
			state.opacity = clampNumber(options.opacity, 0.15, 1, state.opacity)
		end
		if type(options.position) == "table" then
			state.position.x = math.max(0, math.floor(tonumber(options.position.x or options.position.X) or state.position.x))
			state.position.y = math.max(0, math.floor(tonumber(options.position.y or options.position.Y) or state.position.y))
			state.dock = "custom"
		end
		if type(options.size) == "table" then
			state.size.width = math.max(220, math.floor(tonumber(options.size.width or options.size.w) or state.size.width))
			state.size.height = math.max(140, math.floor(tonumber(options.size.height or options.h) or state.size.height))
			state.dock = "custom"
		end
		if options.dock ~= nil then
			local dock = normalizeDock(options.dock)
			state.dock = dock
			if dock ~= "custom" then
				local nextX, nextY = resolveDockPosition(dock)
				state.position.x = nextX
				state.position.y = nextY
			end
		end
		if options.visible ~= nil then
			state.visible = options.visible == true
		end
		updateRootVisual()
		if state.visible then
			updateBody()
		end
		persistState()
		return true, L("hud.status.configured", "Performance HUD configured.")
	end

	local function resetPosition(dock)
		local nextDock = normalizeDock(dock or DEFAULT_DOCK)
		if nextDock == "custom" then
			nextDock = DEFAULT_DOCK
		end
		state.dock = nextDock
		local nextX, nextY = resolveDockPosition(nextDock)
		state.position.x = nextX
		state.position.y = nextY
		updateRootVisual()
		persistState()
		return true, L("hud.status.position_reset", "Performance HUD position reset.")
	end

	local function getStateSnapshot()
		local snapshot = cloneValue(state)
		snapshot.providerCount = 0
		for _ in pairs(providers) do
			snapshot.providerCount += 1
		end
		snapshot.registeredProviders = nil
		return snapshot
	end

	local function registerProvider(id, providerFn, options)
		local key = tostring(id or "")
		if key == "" then
			return false, L("hud.error.provider_id_required", "Provider id is required.")
		end
		if type(providerFn) ~= "function" then
			return false, L("hud.error.provider_must_be_function", "Provider must be a function.")
		end
		providers[key] = {
			fn = providerFn,
			options = type(options) == "table" and cloneValue(options) or {}
		}
		state.registeredProviders[key] = true
		return true, L("hud.status.provider_registered", "HUD provider registered: ") .. key
	end

	local function unregisterProvider(id)
		local key = tostring(id or "")
		if key == "" then
			return false, L("hud.error.provider_id_required", "Provider id is required.")
		end
		providers[key] = nil
		state.registeredProviders[key] = nil
		return true, L("hud.status.provider_removed", "HUD provider removed: ") .. key
	end

	task.spawn(function()
		while destroyed == false do
			local delaySec = 1 / math.max(1, state.updateHz)
			task.wait(delaySec)
			if state.visible then
				ensureGui()
				updateBody()
			end
		end
	end)

	ensureGui()
	if defaultEnabled then
		openHUD()
	else
		state.visible = false
		updateRootVisual()
	end

	local function destroy()
		if destroyed then
			return
		end
		destroyed = true
		disconnectAll()
		if refs.Root then
			pcall(function()
				refs.Root:Destroy()
			end)
		end
	end

	return {
		open = openHUD,
		close = closeHUD,
		toggle = toggleHUD,
		configure = configureHUD,
		resetPosition = resetPosition,
		getState = getStateSnapshot,
		registerProvider = registerProvider,
		unregisterProvider = unregisterProvider,
		destroy = destroy
	}
end

return PerformanceHUDService
]])
put("src/core/runtime/runtime-api.lua", [[local RuntimeApi = {}

function RuntimeApi.bind(context)
	if type(context) ~= "table" then
		error("RuntimeApi.bind expected context table")
	end

	local RayfieldLibrary = context.RayfieldLibrary
	if type(RayfieldLibrary) ~= "table" then
		error("RuntimeApi.bind missing RayfieldLibrary")
	end

	local setVisibility = context.setVisibility
	local getHidden = context.getHidden
	local destroyRuntime = context.destroyRuntime
	local isDestroyed = context.isDestroyed

	if type(setVisibility) ~= "function" then
		error("RuntimeApi.bind missing setVisibility")
	end
	if type(getHidden) ~= "function" then
		error("RuntimeApi.bind missing getHidden")
	end
	if type(destroyRuntime) ~= "function" then
		error("RuntimeApi.bind missing destroyRuntime")
	end
	if type(isDestroyed) ~= "function" then
		error("RuntimeApi.bind missing isDestroyed")
	end

	function RayfieldLibrary:SetVisibility(visibility)
		setVisibility(visibility, false)
	end

	function RayfieldLibrary:IsVisible()
		return not getHidden()
	end

	function RayfieldLibrary:Destroy()
		return destroyRuntime()
	end

	function RayfieldLibrary:IsDestroyed()
		return isDestroyed()
	end
end

return RuntimeApi
]])
put("src/core/runtime/share-code-service.lua", [[local ShareCodeService = {}

local BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"

local function trimString(value)
	value = tostring(value or "")
	value = value:gsub("^%s+", "")
	value = value:gsub("%s+$", "")
	return value
end

local function fallbackBase64Encode(input)
	local source = tostring(input or "")
	local bits = source:gsub(".", function(character)
		local byteValue = string.byte(character)
		local chunk = ""
		for index = 8, 1, -1 do
			if byteValue % (2 ^ index) - byteValue % (2 ^ (index - 1)) > 0 then
				chunk = chunk .. "1"
			else
				chunk = chunk .. "0"
			end
		end
		return chunk
	end)

	local paddedBits = bits .. "0000"
	local encoded = paddedBits:gsub("%d%d%d?%d?%d?%d?", function(chunk)
		if #chunk < 6 then
			return ""
		end
		local value = 0
		for index = 1, 6 do
			if chunk:sub(index, index) == "1" then
				value = value + 2 ^ (6 - index)
			end
		end
		return BASE64_ALPHABET:sub(value + 1, value + 1)
	end)

	return encoded .. ({ "", "==", "=" })[#source % 3 + 1]
end

local function fallbackBase64Decode(input)
	local source = tostring(input or "")
	source = source:gsub("%s+", "")
	source = source:gsub("[^" .. BASE64_ALPHABET .. "=]", "")

	local bits = source:gsub(".", function(character)
		if character == "=" then
			return ""
		end
		local index = BASE64_ALPHABET:find(character, 1, true)
		if not index then
			return ""
		end
		local value = index - 1
		local chunk = ""
		for bit = 6, 1, -1 do
			if value % (2 ^ bit) - value % (2 ^ (bit - 1)) > 0 then
				chunk = chunk .. "1"
			else
				chunk = chunk .. "0"
			end
		end
		return chunk
	end)

	return bits:gsub("%d%d%d?%d?%d?%d?%d?%d?", function(chunk)
		if #chunk ~= 8 then
			return ""
		end
		local value = 0
		for index = 1, 8 do
			if chunk:sub(index, index) == "1" then
				value = value + 2 ^ (8 - index)
			end
		end
		return string.char(value)
	end)
end

local function defaultGeneratedAt()
	local okDate, value = pcall(function()
		return os.date("!%Y-%m-%dT%H:%M:%SZ")
	end)
	if okDate and type(value) == "string" then
		return value
	end
	local okTick, tickValue = pcall(function()
		return tostring(math.floor((tick and tick() or 0) * 1000))
	end)
	if okTick and type(tickValue) == "string" then
		return tickValue
	end
	return "unknown"
end

function ShareCodeService.create(options)
	options = type(options) == "table" and options or {}
	local httpService = options.HttpService
	local configSystem = options.ConfigSystem
	local settingsSystem = options.SettingsSystem
	local uiStateSystem = options.UIStateSystem
	local localizationService = options.LocalizationService
	local interfaceBuild = tostring(options.InterfaceBuild or "")
	local release = tostring(options.Release or "")
	local shareCodePrefix = tostring(options.SHARE_CODE_PREFIX or "RFSC1:")
	local sharePayloadVersion = tonumber(options.SHARE_PAYLOAD_VERSION) or 1
	local sharePayloadType = tostring(options.SHARE_PAYLOAD_TYPE or "rayfield_share")
	local generatedAtProvider = type(options.buildGeneratedAtStamp) == "function" and options.buildGeneratedAtStamp or defaultGeneratedAt

	local activeShareCode = ""
	local activeSharePayload = nil
	local pendingForeignDisplay = nil

	local service = {}

	local function encodeBase64(input)
		if httpService and type(httpService.Base64Encode) == "function" then
			local okEncoded, encoded = pcall(httpService.Base64Encode, httpService, input)
			if okEncoded and type(encoded) == "string" then
				return true, encoded
			end
		end
		local okFallback, encoded = pcall(fallbackBase64Encode, input)
		if not okFallback then
			return false, tostring(encoded)
		end
		return true, encoded
	end

	local function decodeBase64(input)
		if httpService and type(httpService.Base64Decode) == "function" then
			local okDecoded, decoded = pcall(httpService.Base64Decode, httpService, input)
			if okDecoded and type(decoded) == "string" then
				return true, decoded
			end
		end
		local okFallback, decoded = pcall(fallbackBase64Decode, input)
		if not okFallback then
			return false, tostring(decoded)
		end
		return true, decoded
	end

	local function validateSharePayload(payload)
		if type(payload) ~= "table" then
			return false, "Share code payload is invalid."
		end
		if payload.type ~= sharePayloadType then
			return false, "Share code payload type is invalid."
		end
		if tonumber(payload.version) ~= sharePayloadVersion then
			return false, "Share code version is unsupported."
		end
		if type(payload.configuration) ~= "table" then
			return false, "Share code is missing configuration data."
		end
		if type(payload.internalSettings) ~= "table" then
			return false, "Share code is missing internal settings data."
		end
		return true
	end

	local function notifyShareCodeStatus(success, message)
		if not uiStateSystem or type(uiStateSystem.Notify) ~= "function" then
			return
		end
		local content = tostring(message or "")
		if content == "" then
			if success then
				content = "Share code operation completed."
			else
				content = "Share code operation failed."
			end
		end
		pcall(uiStateSystem.Notify, {
			Title = "Rayfield Share Code",
			Content = content,
			Image = success and 4483362458 or 4384402990
		})
	end

	local function setActiveSharePayload(code, payload)
		activeShareCode = tostring(code or "")
		activeSharePayload = payload
		pendingForeignDisplay = nil
		if settingsSystem and type(settingsSystem.setShareCodeInputValue) == "function" then
			pcall(settingsSystem.setShareCodeInputValue, activeShareCode)
		end
	end

	local function encodeSharePayload(payload)
		local okJson, jsonOrErr = pcall(function()
			return httpService:JSONEncode(payload)
		end)
		if not okJson or type(jsonOrErr) ~= "string" then
			return nil, "Failed to encode share payload."
		end

		local okBase64, encodedOrErr = encodeBase64(jsonOrErr)
		if not okBase64 then
			return nil, "Failed to encode share payload as Base64."
		end

		return shareCodePrefix .. encodedOrErr
	end

	local function decodeShareCode(code)
		local normalized = trimString(code)
		if normalized == "" then
			return false, "Share code cannot be empty."
		end
		if normalized:sub(1, #shareCodePrefix) ~= shareCodePrefix then
			return false, "Share code prefix is invalid."
		end

		local encodedBody = normalized:sub(#shareCodePrefix + 1):gsub("%s+", "")
		if encodedBody == "" then
			return false, "Share code payload is empty."
		end

		local okDecode, decodedOrErr = decodeBase64(encodedBody)
		if not okDecode or type(decodedOrErr) ~= "string" then
			return false, "Share code Base64 payload is invalid."
		end

		local okJson, payloadOrErr = pcall(function()
			return httpService:JSONDecode(decodedOrErr)
		end)
		if not okJson or type(payloadOrErr) ~= "table" then
			return false, "Share code JSON payload is invalid."
		end

		return true, shareCodePrefix .. encodedBody, payloadOrErr
	end

	function service.getActiveShareCode()
		return activeShareCode
	end

	function service.getActiveSharePayload()
		return activeSharePayload
	end

	function service.notifyStatus(success, message)
		notifyShareCodeStatus(success == true, message)
	end

	function service.importCode(code)
		local okDecode, canonicalOrMessage, payload = decodeShareCode(code)
		if not okDecode then
			return false, tostring(canonicalOrMessage)
		end

		local validPayload, payloadMessage = validateSharePayload(payload)
		if not validPayload then
			return false, tostring(payloadMessage)
		end

		setActiveSharePayload(canonicalOrMessage, payload)
		if localizationService and type(localizationService.detectForeignDisplay) == "function" then
			local okDetect, isForeign, detectMeta = pcall(localizationService.detectForeignDisplay, payload)
			if okDetect and isForeign == true then
				pendingForeignDisplay = type(detectMeta) == "table" and detectMeta or {
					languageTag = "unknown",
					hasCustomLabels = true
				}
			else
				pendingForeignDisplay = nil
			end
		end
		return true, "Share code imported."
	end

	function service.importSettings(importOptions)
		if type(activeSharePayload) ~= "table" then
			return false, "No active share code. Import code first."
		end

		local validPayload, payloadMessage = validateSharePayload(activeSharePayload)
		if not validPayload then
			return false, tostring(payloadMessage)
		end
		importOptions = type(importOptions) == "table" and importOptions or {}

		local foreignMeta = pendingForeignDisplay
		if localizationService and type(localizationService.detectForeignDisplay) == "function" then
			local okDetect, isForeign, detectMeta = pcall(localizationService.detectForeignDisplay, activeSharePayload)
			if okDetect and isForeign == true then
				foreignMeta = type(detectMeta) == "table" and detectMeta or foreignMeta
			else
				foreignMeta = nil
			end
		end
		if foreignMeta and importOptions.confirmForeignDisplay ~= true then
			pendingForeignDisplay = foreignMeta
			local languageTag = tostring(foreignMeta.languageTag or "unknown")
			return false, "Foreign display language detected. Confirm required.", {
				confirmRequired = true,
				languageTag = languageTag,
				hasCustomLabels = foreignMeta.hasCustomLabels == true
			}
		end

		if not configSystem or type(configSystem.ImportConfigurationData) ~= "function" then
			return false, "Configuration import is unavailable."
		end
		if not settingsSystem or type(settingsSystem.ImportInternalSettingsData) ~= "function" then
			return false, "Internal settings import is unavailable."
		end

		local okConfig, configSuccess, configDetail = pcall(configSystem.ImportConfigurationData, activeSharePayload.configuration)
		if not okConfig then
			return false, "Failed to apply configuration data: " .. tostring(configSuccess)
		end
		if configSuccess ~= true then
			return false, tostring(configDetail or "Failed to apply configuration data.")
		end

		local okInternal, internalSuccess, internalDetail = pcall(settingsSystem.ImportInternalSettingsData, activeSharePayload.internalSettings)
		if not okInternal then
			return false, "Failed to apply internal settings: " .. tostring(internalSuccess)
		end
		if internalSuccess ~= true then
			return false, tostring(internalDetail or "Failed to apply internal settings.")
		end

		if localizationService and type(localizationService.importScopePack) == "function" then
			local incomingLocalization = activeSharePayload.localization
			if type(incomingLocalization) == "table" then
				local okLocImport, locSuccess, locMessage = pcall(localizationService.importScopePack, incomingLocalization, {
					merge = false
				})
				if not okLocImport then
					return false, "Failed to apply localization payload: " .. tostring(locSuccess)
				end
				if locSuccess ~= true then
					return false, tostring(locMessage or "Failed to apply localization payload.")
				end
			end
		end
		pendingForeignDisplay = nil

		local persistenceWarnings = {}
		if configSystem and type(configSystem.SaveConfigurationForced) == "function" then
			local okPersistConfig, persistedConfig = pcall(configSystem.SaveConfigurationForced)
			if not okPersistConfig or persistedConfig == false then
				table.insert(persistenceWarnings, "configuration")
			end
		end
		if settingsSystem and type(settingsSystem.saveSettings) == "function" then
			local okPersistSettings, persistedSettings = pcall(settingsSystem.saveSettings)
			if not okPersistSettings or persistedSettings == false then
				table.insert(persistenceWarnings, "internal settings")
			end
		end

		if #persistenceWarnings > 0 then
			return true, "Share settings applied, but persistence failed for: " .. table.concat(persistenceWarnings, ", ") .. "."
		end

		local changedConfiguration = configDetail == true
		local appliedInternalCount = tonumber(internalDetail) or 0
		if changedConfiguration or appliedInternalCount > 0 then
			return true, "Share settings applied."
		end
		return true, "Share settings were already up to date."
	end

	function service.exportSettings()
		if not configSystem or type(configSystem.ExportConfigurationData) ~= "function" then
			return nil, "Configuration export is unavailable."
		end
		if not settingsSystem or type(settingsSystem.ExportInternalSettingsData) ~= "function" then
			return nil, "Internal settings export is unavailable."
		end

		local okConfig, configurationData = pcall(configSystem.ExportConfigurationData)
		if not okConfig or type(configurationData) ~= "table" then
			return nil, "Failed to collect configuration data."
		end
		local okSettings, internalSettingsData = pcall(settingsSystem.ExportInternalSettingsData)
		if not okSettings or type(internalSettingsData) ~= "table" then
			return nil, "Failed to collect internal settings data."
		end

		local payload = {
			type = sharePayloadType,
			version = sharePayloadVersion,
			configuration = configurationData,
			internalSettings = internalSettingsData,
			meta = {
				generatedAt = tostring(generatedAtProvider() or "unknown"),
				interfaceBuild = interfaceBuild,
				release = release
			}
		}
		if localizationService and type(localizationService.exportScopePack) == "function" then
			local okLocExport, localizationPayload = pcall(localizationService.exportScopePack, {
				asJson = false
			})
			if okLocExport and type(localizationPayload) == "table" then
				payload.localization = localizationPayload
			end
			if type(localizationService.getMetaForShare) == "function" then
				local okMeta, meta = pcall(localizationService.getMetaForShare)
				if okMeta and type(meta) == "table" then
					payload.meta.localization = meta
				end
			end
		end

		local encodedCode, encodedErr = encodeSharePayload(payload)
		if type(encodedCode) ~= "string" then
			return nil, tostring(encodedErr or "Failed to export share code.")
		end

		setActiveSharePayload(encodedCode, payload)
		return encodedCode, "ok"
	end

	function service.copyShareCode(suppressNotify)
		local shouldNotify = suppressNotify ~= true
		if type(activeShareCode) ~= "string" or activeShareCode == "" then
			local message = "No active share code. Export or import a code first."
			if shouldNotify then
				notifyShareCodeStatus(false, message)
			end
			return false, message
		end

		local clipboardWriter = nil
		if type(setclipboard) == "function" then
			clipboardWriter = setclipboard
		elseif type(toclipboard) == "function" then
			clipboardWriter = toclipboard
		end

		if type(clipboardWriter) ~= "function" then
			if settingsSystem and type(settingsSystem.setShareCodeInputValue) == "function" then
				pcall(settingsSystem.setShareCodeInputValue, activeShareCode)
			end
			local message = "Clipboard is unavailable. Share code was placed in the Share Code input."
			if shouldNotify then
				notifyShareCodeStatus(false, message)
			end
			return false, message
		end

		local okCopy, copyErr = pcall(clipboardWriter, activeShareCode)
		if not okCopy then
			if settingsSystem and type(settingsSystem.setShareCodeInputValue) == "function" then
				pcall(settingsSystem.setShareCodeInputValue, activeShareCode)
			end
			local message = "Failed to copy share code: " .. tostring(copyErr)
			if shouldNotify then
				notifyShareCodeStatus(false, message)
			end
			return false, message
		end

		local message = "Share code copied to clipboard."
		if shouldNotify then
			notifyShareCodeStatus(true, message)
		end
		return true, message
	end

	return service
end

return ShareCodeService
