		ResolveChartBuilderModule = resolveChartBuilderModule,
		RangeBarsFactoryModule = getLoadedRuntimeModule("elementsRangeBarsFactory"),
		ResolveRangeBarsFactoryModule = resolveRangeBarsFactoryModule,
