		ResolveFeedbackWidgetsFactoryModule = resolveFeedbackWidgetsFactoryModule,
		ButtonFactoryModule = getLoadedRuntimeModule("elementsButtonFactory"),
		ResolveButtonFactory = resolveButtonFactoryModule,
